code = """import json

# Load all articles
articles_path = locals()['var_functions.query_db:48']
with open(articles_path, 'r') as f:
    articles = json.load(f)

# Search for very specific well-known sports entities
well_known_sports = [
    "lakers", "yankees", "manchester united", "real madrid", "barcelona",
    "federer", "nadal", "jordan", "lebron", "messi", "ronaldo",
    "super bowl", "world series", "nba finals", "world cup", "olympics",
    "michael phelps", "tiger woods", "serena williams", "tom brady"
]

# Search in titles and descriptions
found_sports_articles = []

for article in articles:
    title_lower = article.get("title", "").lower()
    desc_lower = article.get("description", "").lower()
    full_text = title_lower + " " + desc_lower
    
    # Check for well-known sports entities
    for entity in well_known_sports:
        if entity in full_text:
            found_sports_articles.append({
                "title": article.get("title"),
                "description": article.get("description"),
                "entity": entity
            })
            break

print(f"Found {len(found_sports_articles)} articles with well-known sports entities")

if found_sports_articles:
    print("\nSports articles found:")
    for article in found_sports_articles[:10]:
        print(f"Entity: {article['entity']}")
        print(f"Title: {article['title']}")
        print(f"Description: {article['description'][:150]}...")
        print("-" * 50)
else:
    print("No well-known sports entities found in the dataset")
    
    # Let's check what topics are actually in the data
    print("\n\nAnalyzing article topics from first 100 titles:")
    for i in range(min(100, len(articles))):
        print(f"{i}: {articles[i]['title']}")

result = "No sports articles found" if not found_sports_articles else "Found some sports articles"
print("__RESULT__:")
print(json.dumps(result))"""

